pub fn rotate_right<T: Clone>(arr: &mut [T], k: usize) {
    let n = arr.len();
    if n == 0 {
        return;
    }

    let k = k % n;
    if k == 0 {
        return;
    }

    let mut temp = arr[n - k..].to_vec();
    for i in (0..n - k).rev() {
        arr[i + k] = arr[i].clone();
    }

    for i in 0..k {
        arr[i] = temp[i].clone();
    }
}

